(function() {
  /* ── 1. Data source ── */
  const data = migratepush.data; // change to your actual query name

  let html = '';
  let inSection = false;

  /* ── 2. Iterate rows and build HTML ── */
  data.forEach(function(row) {
    const keys = Object.keys(row);

    /* 2a. Section start */
    if (keys.includes('Start:')) {
      inSection = true;
      html += '<div style="border:1px solid #ccc; border-radius:8px; padding:12px; margin-bottom:12px; background:#f9f9f9;">';
      html += '<h3 style="margin:0 0 8px 0; color:#2c3e50; border-bottom:2px solid #3498db; padding-bottom:4px;">' + row['Start:'] + '</h3>';
      return;
    }

    /* 2b. Section end */
    if (keys.includes('End:')) {
      html += '<p style="margin:4px 0 0 0; font-size:0.85em; color:#888;">' + row['End:'] + '</p>';
      html += '</div>';
      inSection = false;
      return;
    }

    /* 2c. Data rows inside a section */
    if (inSection) {
      html += '<table style="width:100%; margin-bottom:6px; font-size:0.9em;">';
      keys.forEach(function(key) {
        let val = row[key];

        /* 2c-i. Try to parse nested JSON strings */
        if (typeof val === 'string' && val.startsWith('{')) {
          try {
            const parsed = JSON.parse(val);
            val = Object.keys(parsed).map(function(k) {
              return '<b>' + k + ':</b> ' + parsed[k];
            }).join(', ');
          } catch(e) {
            /* leave val as-is */
          }
        }

        html += '<tr>';
        html += '<td style="padding:2px 8px 2px 0; font-weight:bold; color:#555; white-space:nowrap; vertical-align:top; width:40%;">' + key + '</td>';
        html += '<td style="padding:2px 0; color:#222;">' + val + '</td>';
        html += '</tr>';
      });
      html += '</table>';
    }
  });

  return html;
})()
}}
